         ELSE
            RT_9 =  1.0E10 * I_RSC
         ENDIF
      ELSE
         RT_9 = I_RSC / Inom_Rtr_pk
      ENDIF
!

! 1080:[datatap] Scalar/Array Tap 
      RT_12 = RT_9(1)

! 1090:[datatap] Scalar/Array Tap 
      RT_13 = RT_9(2)

! 1100:[datatap] Scalar/Array Tap 
      RT_14 = RT_9(3)

! 1110:[mult] Multiplier 
      RT_36 = Pref_pu * Low_Cu_Manag

! 1120:[sumjct] Summing/Differencing Junctions 
      Vst1_a_ = - RT_58 + Vst1_a

! 1130:[tvekta] Phase-Locked Loop 
      RVD1_1 = -1.570796327
      CALL COMPONENT_ID(ICALL_NO,508324241)
      CALL TVEKA1_EXE(Vst1_a_,Vst1_b_,Vst1_c_,Kp_PLL_DFIG,Ki_PLL_DFIG,RV&
     &D1_1,0.85,1.15,0.85,phisPLL,RVD1_3,RVD1_2)
      Freq_PLL = RVD1_2
!

! 1140:[sumjct] Summing/Differencing Junctions 
      RT_11 = + phisPLL - Theta

! 1150:[angle_resolver] Angle Resolver 

      slpang = ATAN2(SIN(RT_11),COS(RT_11))
      IF (slpang .LE. 0.0) THEN
        slpang = slpang + TWO_PI
      ENDIF

! 1160:[abcdq0] abc dq0 transformation 
!ABC to DQ0 transformation
      CALL TRDQO(RT_12,RT_13,RT_14,RT_15,RT_16,RT_17,slpang,1)

! 1170:[complex] Second Order Complex Pole 
! Second Order Complex Pole
      RVD1_1 = TWO_PI*500.0
      RT_10 = CMPX2ORD(1, 1.0, DmpR, RVD1_1, RT_16)
!

! 1180:[gain] Gain Block 
!  Gain
      Iqr_pu = -1.0 * RT_10

! 1190:[select] Two Input Selector 
      IF (Synch_St .EQ. RTCI(NRTCI)) THEN
         Iq_lim_max = Iqr_pu
      ELSE
         Iq_lim_max = Imax_pu
      ENDIF
      NRTCI = NRTCI + 1
!

! 1200:[select] Two Input Selector 
      IF (Synch_St .EQ. RTCI(NRTCI)) THEN
         Iq_lim_min = Iqr_pu
      ELSE
         Iq_lim_min = Imax_Neg_pu
      ENDIF
      NRTCI = NRTCI + 1
!

! 1210:[abcdq0] abc dq0 transformation 
!ABC to DQ0 transformation
      CALL TRDQO(Vst1_a,Vst1_b,Vst1_c,V1d_pu,V1q_pu,RT_53,phisPLL,1)

! 1220:[sumjct] Summing/Differencing Junctions 
      RT_1 = + Pg_pu - RT_36

! 1230:[div] Divider 
!
      IF (ABS(TRN) .LT. 1.0E-10) THEN
         IF (TRN .LT. 0.0)  THEN
            RT_40 = -1.0E10 * V1d_pu
         ELSE
            RT_40 =  1.0E10 * V1d_pu
         ENDIF
      ELSE
         RT_40 = V1d_pu / TRN
      ENDIF
!

! 1240:[mult] Multiplier 
      RT_54 = V1d_pu * RT_55

! 1250:[mult] Multiplier 
      RT_42 = RT_40 * Delta_w

! 1260:[gain] Gain Block 
!  Gain
      vdref_st_pu = -1.0 * RT_54

! 1270:[div] Divider 
!
      IF (ABS(TRN) .LT. 1.0E-10) THEN
         IF (TRN .LT. 0.0)  THEN
            RT_41 = -1.0E10 * V1q_pu
         ELSE
            RT_41 =  1.0E10 * V1q_pu
         ENDIF
      ELSE
         RT_41 = V1q_pu / TRN
      ENDIF
!

! 1280:[mult] Multiplier 
      RT_37 = RT_41 * Delta_w

! 1290:[PI_AntiWindUp]  
      CALL PI_AntiWindUpDyn(RT_7, Iqref_pu, Voltage_dip, Re_Set, KpQ, Ti&
     &Q, 1.0, Iq_lim_max, Iq_lim_min)


! 1300:[sumjct] Summing/Differencing Junctions 
      RT_5 = + Iqref_pu - Iqr_pu

! 1310:[PI_AntiWindUp]  
      CALL PI_AntiWindUpDyn(RT_5, RT_6, IT_3, Re_Set, Kpq_R, Tiq_R, 1.0,&
     & Vq_lim_max, Vq_lim_min)


! 1320:[select] Two Input Selector 
      IF (Synch_St .EQ. RTCI(NRTCI)) THEN
         Vd_lim_max = vdref_st_pu
      ELSE
         Vd_lim_max = Vmax_pu
      ENDIF
      NRTCI = NRTCI + 1
!

! 1330:[select] Two Input Selector 
      IF (Synch_St .EQ. RTCI(NRTCI)) THEN
         Vd_lim_min = vdref_st_pu
      ELSE
         Vd_lim_min = Vmax_Neg_pu
      ENDIF
      NRTCI = NRTCI + 1
!

! 1340:[square] Square 
      RT_44 = Iqref_pu * Iqref_pu

! 1350:[complex] Second Order Complex Pole 
! Second Order Complex Pole
      RVD1_1 = TWO_PI*500.0
      Idr_pu = CMPX2ORD(1, 1.0, DmpR, RVD1_1, RT_15)
!

! 1360:[sumjct] Summing/Differencing Junctions 
      RT_45 = + RT_43 - RT_44

! 1370:[sqrt] Square Root 
      IF (RT_45 .LE. 0.0) THEN
         RT_46 = 0.0
      ELSE
         RT_46 = SQRT(RT_45)
      ENDIF

! 1380:[ratelimit] Rate Limiter 
!  Rate_Limiter
      CALL RATE_LIMITER(1.0,1000.0,RT_46,Imax_d_pu)

! 1390:[gain] Gain Block 
!  Gain
      ImaxN_d_pu = -1.0 * Imax_d_pu

! 1400:[sumjct] Summing/Differencing Junctions 
      RT_20 = + RT_6 - RT_37

! 1410:[select] Two Input Selector 
      IF (Synch_St .EQ. RTCI(NRTCI)) THEN
         vqref_pu = RT_20
      ELSE
         vqref_pu = vqref_st_pu
      ENDIF
      NRTCI = NRTCI + 1
!

! 1420:[select] Two Input Selector 
      IF (Synch_St .EQ. RTCI(NRTCI)) THEN
         Id_lim_max = Idr_pu
      ELSE
         Id_lim_max = Imax_d_pu
      ENDIF
      NRTCI = NRTCI + 1
!

! 1430:[select] Two Input Selector 
      IF (Synch_St .EQ. RTCI(NRTCI)) THEN
         Id_lim_min = Idr_pu
      ELSE
         Id_lim_min = ImaxN_d_pu
      ENDIF
      NRTCI = NRTCI + 1
!

! 1440:[PI_AntiWindUp]  
      CALL PI_AntiWindUpDyn(RT_1, Idref_pu, IT_1, Re_Set, KpP, TiP, 1.0,&
     & Id_lim_max, Id_lim_min)


! 1450:[sumjct] Summing/Differencing Junctions 
      RT_3 = + Idref_pu - Idr_pu

! 1460:[PI_AntiWindUp]  
      CALL PI_AntiWindUpDyn(RT_3, RT_4, IT_2, Re_Set, Kpd_R, Tid_R, 2.0,&
     & Vd_lim_max, Vd_lim_min)


! 1470:[sumjct] Summing/Differencing Junctions 
      RT_19 = + RT_4 - RT_42

! 1480:[select] Two Input Selector 
      IF (Synch_St .EQ. RTCI(NRTCI)) THEN
         vdref_pu = RT_19
      ELSE
         vdref_pu = vdref_st_pu
      ENDIF
      NRTCI = NRTCI + 1
!

! 1490:[polar_rec] Polar Rectangular coordinate converter 
      RT_29 = SQRT(vdref_pu*vdref_pu+vqref_pu*vqref_pu)
      IF ((ABS(vdref_pu).GT.1.0E-20).OR.(ABS(vqref_pu).GT.1.0E-20)) THEN
        RT_25 = ATAN2(vqref_pu,vdref_pu)
      ELSE
        RT_25 = 0.0
      ENDIF

! 1500:[mult] Multiplier 
      RT_28 = RT_29 * M_kv_peak

! 1510:[div] Divider 
!
      IF (ABS(RT_21) .LT. 1.0E-10) THEN
         IF (RT_21 .LT. 0.0)  THEN
            RT_30 = -1.0E10 * RT_28
         ELSE
            RT_30 =  1.0E10 * RT_28
         ENDIF
      ELSE
         RT_30 = RT_28 / RT_21
      ENDIF
!

! 1520:[hardlimit] Hard Limiter 
!  Hard_Limit
      IF (0.0 .LE. 1.15) THEN
        RT_23 = LIMIT(0.0, 1.15, RT_30)
      ELSE
        RT_23 = RT_30
        IF (STORL(NSTORL) .EQV. .FALSE.) THEN
          CALL EMTDC_WARN(ICALL_NO,462474141,1,"Lower limit is more than&
     & the upper limit, limits not enforced.")
          STORL(NSTORL) = .TRUE.
        ENDIF
