      NSTORL = NSTORL + 1
!

! 1530:[polar_rec] Polar Rectangular coordinate converter 
      RT_22 = RT_23*COS(RT_25)
      RT_24 = RT_23*SIN(RT_25)

! 1540:[gain] Gain Block 
!  Gain
      RT_26 = -1.0 * RT_24

! 1550:[abcdq0] abc dq0 transformation 
!DQ0 to ABC transformation
      CALL TRDQO(Va_ref_pu,Vb_ref_pu,Vc_ref_pu,RT_22,RT_26,RT_27,slpang,&
     &-1)

! 1560:[datamerge] Merges data signals into an array 
      RS_VREF_pu(1) = Va_ref_pu
      RS_VREF_pu(2) = Vb_ref_pu
      RS_VREF_pu(3) = Vc_ref_pu

! 1570:[abcdq0] abc dq0 transformation 
