      CALL TRDQO(RT_49,RT_50,RT_51,Vsd_pu,Vsq_pu,RT_52,phisPLL,1)

! 1580:[pgb] Output Channel 'vdref_st'

      PGB(IPGB+11) = vdref_st_pu

! 1590:[pgb] Output Channel 'vqref_pu'

      PGB(IPGB+12) = vqref_pu

